"""Тесты обработчика секции pipeline (PipelineConfig в sections)."""from src.modules.project.sections.pipeline_config import (    CREATE_DOCUMENTS_INDEX_DEFAULT,    EXTRACT_THREADS_DEFAULT,    IMAGE_PROCESSING_THREADS_DEFAULT,    KEY_CREATE_DOCUMENTS_INDEX,    KEY_DISCOVERY_THREADS,    KEY_EXTRACT_THREADS,    KEY_IMAGE_PROCESSING_THREADS,    KEY_MARKDOWN_THREADS,    KEY_TAGGING_THREADS,    MARKDOWN_THREADS_DEFAULT,    TAGGING_THREADS_DEFAULT,    PipelineConfig,)def test_get_default_returns_expected_values() -> None:    """Умолчания: discovery=1, extract/image/md/tagging по константам."""    default = PipelineConfig.get_default()    assert default[KEY_DISCOVERY_THREADS] == 1    assert default[KEY_EXTRACT_THREADS] == EXTRACT_THREADS_DEFAULT    assert default[KEY_IMAGE_PROCESSING_THREADS] == IMAGE_PROCESSING_THREADS_DEFAULT    assert default[KEY_MARKDOWN_THREADS] == MARKDOWN_THREADS_DEFAULT    assert default[KEY_TAGGING_THREADS] == TAGGING_THREADS_DEFAULT    assert default[KEY_CREATE_DOCUMENTS_INDEX] is CREATE_DOCUMENTS_INDEX_DEFAULTdef test_validate_valid_data_returns_empty_list() -> None:    """Валидные значения не дают ошибок."""    assert PipelineConfig.validate(PipelineConfig.get_default()) == []    assert PipelineConfig.validate({KEY_DISCOVERY_THREADS: 1, KEY_EXTRACT_THREADS: 8, KEY_IMAGE_PROCESSING_THREADS: 4}) == []def test_validate_non_dict_returns_error() -> None:    """Не-словарь даёт ошибку."""    errors = PipelineConfig.validate(None)    assert len(errors) == 1    assert "объект" in errors[0] or "dict" in errors[0]def test_validate_discovery_threads_must_be_one() -> None:    """discovery_threads допускает только 1."""    assert PipelineConfig.validate({KEY_DISCOVERY_THREADS: 2}) != []    assert PipelineConfig.validate({KEY_DISCOVERY_THREADS: 1}) == []def test_validate_extract_threads_range() -> None:    """extract_threads: 1–16."""    assert PipelineConfig.validate({KEY_EXTRACT_THREADS: 0}) != []    assert PipelineConfig.validate({KEY_EXTRACT_THREADS: 17}) != []    assert PipelineConfig.validate({KEY_EXTRACT_THREADS: 1}) == []    assert PipelineConfig.validate({KEY_EXTRACT_THREADS: 16}) == []def test_validate_image_processing_threads_range() -> None:    """image_processing_threads: 1–8."""    assert PipelineConfig.validate({KEY_IMAGE_PROCESSING_THREADS: 0}) != []    assert PipelineConfig.validate({KEY_IMAGE_PROCESSING_THREADS: 9}) != []    assert PipelineConfig.validate({KEY_IMAGE_PROCESSING_THREADS: 1}) == []    assert PipelineConfig.validate({KEY_IMAGE_PROCESSING_THREADS: 8}) == []def test_validate_create_documents_index_must_be_bool() -> None:    """create_documents_index — только bool."""    assert PipelineConfig.validate({KEY_CREATE_DOCUMENTS_INDEX: "yes"}) != []    assert PipelineConfig.validate({KEY_CREATE_DOCUMENTS_INDEX: True}) == []def test_validate_tagging_threads_range() -> None:    """tagging_threads: 1–8."""    assert PipelineConfig.validate({KEY_TAGGING_THREADS: 0}) != []    assert PipelineConfig.validate({KEY_TAGGING_THREADS: 9}) != []    assert PipelineConfig.validate({KEY_TAGGING_THREADS: 1}) == []    assert PipelineConfig.validate({KEY_TAGGING_THREADS: 8}) == []